import{_ as t,o,c as n,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"18. Consultation","description":"","frontmatter":{"title":"18. Consultation","eba":"Mental Health Services 2024-2028","topics":["leave","parental-leave","consultation","ohs","workers-comp"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/consultation-disputes/18-consultation.md","filePath":"ebas/mental-health/common-terms/consultation-disputes/18-consultation.md"}'),i={name:"ebas/mental-health/common-terms/consultation-disputes/18-consultation.md"};function r(a,e,p,l,h,c){return o(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="_18-consultation" tabindex="-1">18. Consultation <a class="header-anchor" href="#_18-consultation" aria-label="Permalink to &quot;18. Consultation&quot;">​</a></h1><p>Nothing in this clause limits the Employer’s obligations to consult with HSRs under the OHS Act.</p><p><strong>18.1</strong> Consultation regarding Major Change</p><p><strong>(a)</strong> Where an Employer proposes a Major Change that may have a Significant Effect on an Employee or Employees, the Employer will consult with the Affected Employee/s, the Unions, and the Employee’s other chosen representative (where relevant) before any proposed change occurs.</p><p><strong>(b)</strong> Consultation will, where reasonably practicable, include consultation with those who are absent on leave including on workers&#39; compensation or parental leave.</p><p><strong>(c)</strong> The Employer will take reasonable steps to ensure Employees, HSRs (where relevant) and the Unions can participate effectively in the Consultation process.</p><p><strong>18.2</strong> Definitions Under this clause 18</p><p><strong>(a)</strong> Consultation means a genuine opportunity to influence the decision maker, but not joint decision making. It is not merely an announcement as to what is about to happen.</p><p><strong>(b)</strong> Affected Employee means an Employee on whom a Major Change may have a Significant Effect.</p><p><strong>(c)</strong> Major Change means a change (including a temporary or urgent change) in the Employer’s program, production, organisation, physical workplace, workplace arrangements, structure or technology that is likely to have a Significant Effect on Employees.</p><p><strong>(d)</strong> Significant Effect includes but is not limited to:</p><p><strong>(i)</strong> termination of employment</p><p><strong>(ii)</strong> changes in the size, composition or operation of the Employer’s workforce (including from outsourcing) or skills required</p><p><strong>(iii)</strong> alteration of the number of hours worked and/or reduction in remuneration</p><p><strong>(iv)</strong> changes to an Employee’s classification, position description, duties or reporting lines</p><p><strong>(v)</strong> the need for retraining or relocation/redeployment/transfer to another site or to other work</p><p><strong>(vi)</strong> removal of an existing amenity; and/or</p><p><strong>(vii)</strong> the removal or reduction of job opportunities, promotion opportunities or job tenure.</p><p><strong>(e)</strong> Measures to mitigate or avert may include but are not limited to:</p><p><strong>(i)</strong> redeployment</p><p><strong>(ii)</strong> retraining</p><p><strong>(iii)</strong> salary maintenance</p><p><strong>(iv)</strong> job sharing; and/or</p><p><strong>(v)</strong> maintenance of accruals.</p><p><strong>18.3</strong> Consultation Steps</p><p><strong>(a)</strong> Consultation includes the steps set out below.</p><p><strong>(b)</strong> Timeframes for each step must allow a party to consultation (including a representative) to genuinely participate in an informed way having regard for all the circumstances including the complexity of the change proposed, and the need for Employees and their representative to meet with each other and consider and discuss the Employer&#39;s proposal. The timeframes in this clause are indicative only.</p><p><strong>(c)</strong> The following table makes clear the relevant steps for the consultation process:</p><p>Step Action</p><ol><li><p>Employer provides change impact statement and other written material required by subclause 18.4</p></li><li><p>Written response from Employees and / or union.</p></li><li><p>Consultation Meeting/s convened</p></li><li><p>Further Employer response (where relevant)</p></li><li><p>Alternative proposal from Employees or Union</p></li><li><p>Employer to consider alternative proposal/s consistent with the obligation to consult and, if applicable, to arrange further meetings with Employees or Union prior to advising of the outcome of consultation</p></li></ol><p><strong>18.4</strong> Change Impact Statement (Step 1)</p><p><strong>(a)</strong> Prior to Consultation required by this clause, the Employer will provide Affected Employee/s and Union with a written Change Impact Statement setting out all relevant information including:</p><p><strong>(i)</strong> the details of proposed change</p><p><strong>(ii)</strong> the reasons for the proposed change</p><p><strong>(iii)</strong> the possible effect of the proposed change on Employees&#39;: <strong>(A)</strong> workload; and <strong>(B)</strong> occupational health and safety impacts matters, such as those set out in <a href="/eba/ebas/mental-health/common-terms/ohs/69-occupational-health-and-safety-workplace-violence.html">Clause 69</a>; Where occupational health and safety impacts are identified, a risk assessment of the potential effects of the change on the health and safety of Employees must be undertaken in consultation with HSRs, and the proposed mitigating actions to be implemented to prevent such effects;</p><p><strong>(iv)</strong> the expected benefit of the change</p><p><strong>(v)</strong> measures the Employer is considering that may mitigate or avert the effects of the proposed change</p><p><strong>(vi)</strong> if relevant to the proposed change, the existing and proposed position descriptions, including new roles, those of the Affected Employees or managers where reporting lines change</p><p><strong>(vii)</strong> the right of an Affected Employee to have a representative including a Union representative at any time during the change process; and</p><p><strong>(viii)</strong> other written material relevant to the reasons for the proposed change (such as consultant reports), excluding material that is commercial in confidence or exposes the Employer to unreasonable legal risk or cannot be disclosed under the Health Services Act 1988 or other legislation.</p><p><strong>(b)</strong> Any concerns by an Affected Employee or their representative regarding whether the Change Impact Statement complies with clause 18.4 will be raised as soon as practicable and before step 2.</p><p><strong>18.5</strong> Employee / Union response (step 2) Following receipt of the change impact statement, Affected Employees and / or the Union may respond in writing to any matter arising from the proposed change.</p><p><strong>18.6</strong> Meetings (step 3)</p><p><strong>(a)</strong> As part of Consultation, the Employer will meet with the Employee/s, the Union and other nominated representative/s (if any) to discuss:</p><p><strong>(i)</strong> the proposed change</p><p><strong>(ii)</strong> proposals to mitigate or avert the impact of the proposed change; and</p><p><strong>(iii)</strong> any matter identified in the written response from the Affected Employees and / or the Union.</p><p><strong>(b)</strong> To avoid doubt, the ‘first meeting’ at step 3 does not limit the number of meetings for Consultation.</p><p><strong>18.7</strong> Employer response (step 4) The Employer will give prompt and genuine consideration to matters arising from Consultation and will provide a written response to the Affected Employees, Union and (where relevant) other representative/s.</p><p><strong>18.8</strong> Alternative proposal (step 5) The Affected Employee/s, the Union and other representative (where relevant) may submit alternative proposal(s) which will take into account the intended objective and benefits of the proposal. Alternative proposals should be submitted in a timely manner so that unreasonable delay may be avoided.</p><p><strong>18.9</strong> Outcome of Consultation (step 6) The Employer will give prompt and genuine consideration to matters arising from Consultation, including an alternative proposal submitted under sub-clause 18.8, and will advise the Affected Employees, the Union and other nominated representatives (if any) in writing of the outcome of Consultation including:</p><p><strong>(a)</strong> whether the Employer intends to proceed with the change proposal</p><p><strong>(b)</strong> any amendment to the change proposal arising from Consultation</p><p><strong>(c)</strong> details of any measures to mitigate or avert the effect of the changes on Affected Employees; and</p><p><strong>(d)</strong> a summary of how matters that have been raised by Affected Employees, the Union and their representatives, including any alternative proposal, have been taken into account.</p><p><strong>18.10</strong> Consultation disputes Any dispute regarding the obligations under this clause will be dealt under the Dispute Resolution provisions at <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/22-disputes-resolution-procedure.html">clause 22</a> of this Agreement.</p><p>18A Central Building Consultative Committee</p><p><strong>18A.1</strong> Where an employer is proposing to undertake construction of a new or significantly changed work area or areas, including construction of a new</p><p>facility, the employer will establish a central building consultative committee for the purpose of consulting with HSRs and the Unions.</p><p><strong>18A.2</strong> The Employer will notify the Unions in writing and invite the Unions to nominate representatives to participate in the central building consultative committee (CBCC). The Employer will make available to the CBCC the information to enable the CBCC to fulfil the intention of this provision.</p><p><strong>18A.3</strong> The CBCC will be responsible for the consultation process. This will include the design elements of the proposed construction from an occupational health and safety perspective.</p><p><strong>184.4</strong> This committee will include representatives from the Employer, HSRs from relevant workplaces, the Unions and other members as relevant, to proactively discuss, review proposals and plans, and provide input for consideration.</p><p><strong>18A.5</strong> Consultation will include:</p><p><strong>(i)</strong> the provision of the building plans once the Employer has the capacity to do so; and</p><p><strong>(ii)</strong> walkthroughs of the site at key stages of development.</p><p><strong>18A.6</strong> The Employer will notify the Unions of the expected timeline for the events listed in subclause 18A.5 as soon as possible to facilitate participation. The Unions will cooperate to ensure such consultation occurs without undue delay to the construction and/or commissioning.</p><p>Plain language terms: consult, consultation obligations, major workplace change.</p>',67)])])}const d=t(i,[["render",r]]);export{m as __pageData,d as default};
